from sympy import legendre_symbol, primerange
def check(p):
    L, a, b = [], 0, 1
    while True:
        L.append(legendre_symbol(a, p))
        a, b = b, (a + b) % p
        if (a, b) == (0, 1): break
    return L.count(1) == L.count(-1) + L.count(0)
print([p for p in primerange(3, 3000) if check(p)])

